-- ═══════════════════════════════════════════════════════════════════════════════
-- PRIVACY POLICY
-- ═══════════════════════════════════════════════════════════════════════════════
INSERT INTO page_sections (page_slug, section_type, display_order, visible, content) VALUES
('privacy-policy', 'rich_text', 1, true, '{
  "heading": "Privacy Policy",
  "badge": "Last Updated: April 2026",
  "html": "<h3>1. Introduction</h3><p>Welcome to Financial Modeler Pro (&ldquo;Platform&rdquo;), operated by PaceMakers Business Consultants LLP (&ldquo;PMBC,&rdquo; &ldquo;we,&rdquo; &ldquo;us,&rdquo; or &ldquo;our&rdquo;), a registered Limited Liability Partnership under SECP Section 7 of the LLP Act, 2017 (Incorporation No.: 0220688, Incorporation Date: 03 January 2023).</p><p>This Privacy Policy explains how we collect, use, store, and protect your personal information when you use our platform at financialmodelerpro.com, learn.financialmodelerpro.com, and app.financialmodelerpro.com.</p><p>For questions about this policy, contact us at <a href=\"mailto:support@financialmodelerpro.com\">support@financialmodelerpro.com</a>.</p><h3>2. Information We Collect</h3><p><strong>Account Information:</strong> When you register, we collect your name, email address, and password (stored as a secure hash &mdash; we never store plain-text passwords).</p><p><strong>Usage Data:</strong> We collect information about how you interact with the Platform, including courses accessed, sessions completed, assessment scores, and progress data.</p><p><strong>Device Information:</strong> For security purposes, we collect device identifiers to manage trusted devices and prevent unauthorized access.</p><p><strong>Communication Data:</strong> When you contact us or subscribe to our newsletter, we collect your email address and any information you provide in your message.</p><h3>3. How We Use Your Information</h3><p>We use your information to:</p><ul><li>Provide and maintain the Platform, including course delivery, assessments, and certification</li><li>Authenticate your identity and secure your account</li><li>Track your learning progress and issue certificates upon completion</li><li>Send transactional emails (account confirmation, password reset, assessment results, certificate issuance)</li><li>Send newsletter updates if you have opted in (you can unsubscribe at any time)</li><li>Improve our Platform and develop new features</li><li>Comply with legal obligations</li></ul><h3>4. Data Storage and Security</h3><p>Your data is stored on secure cloud infrastructure. We implement industry-standard security measures including:</p><ul><li>Encrypted passwords using bcrypt and scrypt hashing algorithms</li><li>HTTP-only secure cookies for session management</li><li>Device verification via one-time passwords (OTPs) for new device logins</li><li>Email confirmation required before account activation</li></ul><p>We retain your data for as long as your account is active or as needed to provide our services. You may request deletion of your account and associated data at any time.</p><h3>5. Third-Party Services</h3><p>We use the following third-party services to operate the Platform:</p><ul><li><strong>Supabase:</strong> Database and file storage</li><li><strong>Vercel:</strong> Website hosting and deployment</li><li><strong>Resend:</strong> Transactional and newsletter email delivery</li><li><strong>hCaptcha:</strong> Bot protection during registration</li><li><strong>YouTube (Google):</strong> Video content delivery and comment display</li><li><strong>Google Sheets:</strong> Student roster management via Apps Script</li></ul><p>These services have their own privacy policies. We only share the minimum data necessary for each service to function.</p><h3>6. Cookies and Local Storage</h3><p>We use cookies and browser storage strictly for functional purposes:</p><ul><li><strong>Authentication cookies:</strong> To keep you signed in (HTTP-only, secure)</li><li><strong>Session storage:</strong> To manage temporary UI state (e.g., dismissing banners)</li><li><strong>Device trust tokens:</strong> To remember verified devices for 30 days</li></ul><p>We do not use advertising cookies or third-party tracking cookies.</p><h3>7. Your Rights</h3><p>You have the right to:</p><ul><li>Access the personal data we hold about you</li><li>Correct inaccurate personal data</li><li>Request deletion of your personal data</li><li>Unsubscribe from newsletter communications at any time</li><li>Request a copy of your data in a portable format</li></ul><p>To exercise any of these rights, contact us at <a href=\"mailto:support@financialmodelerpro.com\">support@financialmodelerpro.com</a>.</p><h3>8. Newsletter Communications</h3><p>When you subscribe to our newsletter, you choose which updates to receive (Training Hub, Modeling Hub, or both). You can unsubscribe from one or both at any time using the unsubscribe link in every email, without affecting your Platform account.</p><h3>9. Children''s Privacy</h3><p>Financial Modeler Pro is a professional educational platform. We do not knowingly collect personal information from children. If you believe a child has provided us with personal data, please contact us and we will delete it promptly.</p><h3>10. Changes to This Policy</h3><p>We may update this Privacy Policy from time to time. We will notify registered users of significant changes via email. The &ldquo;Last Updated&rdquo; date at the top of this page indicates when the policy was last revised.</p><h3>11. Contact Us</h3><p>For any questions or concerns about this Privacy Policy, contact us at:</p><ul><li>Email: <a href=\"mailto:support@financialmodelerpro.com\">support@financialmodelerpro.com</a></li><li>Website: <a href=\"https://financialmodelerpro.com\">financialmodelerpro.com</a></li><li>Parent Company: PaceMakers Business Consultants LLP (<a href=\"https://www.pacemakersglobal.com\">www.pacemakersglobal.com</a>)</li></ul>"
}'::jsonb);

