-- TERMS OF SERVICE
-- ═══════════════════════════════════════════════════════════════════════════════
INSERT INTO page_sections (page_slug, section_type, display_order, visible, content) VALUES
('terms-of-service', 'rich_text', 1, true, '{
  "heading": "Terms of Service",
  "badge": "Last Updated: April 2026",
  "html": "<h3>1. Acceptance of Terms</h3><p>By accessing or using Financial Modeler Pro (&ldquo;Platform&rdquo;), operated by PaceMakers Business Consultants LLP (&ldquo;PMBC,&rdquo; &ldquo;we,&rdquo; &ldquo;us,&rdquo; or &ldquo;our&rdquo;), you agree to be bound by these Terms of Service. If you do not agree to these terms, please do not use the Platform.</p><p>PMBC is a registered Limited Liability Partnership under SECP Section 7 of the LLP Act, 2017 (Incorporation No.: 0220688, Incorporation Date: 03 January 2023).</p><h3>2. Platform Description</h3><p>Financial Modeler Pro provides:</p><ul><li><strong>Training Hub</strong> (learn.financialmodelerpro.com): Financial modeling courses, assessments, and professional certification programs</li><li><strong>Modeling Hub</strong> (app.financialmodelerpro.com): Interactive financial modeling tools and platforms</li><li><strong>Main Site</strong> (financialmodelerpro.com): Company information, articles, and resources</li></ul><h3>3. Account Registration</h3><p>To access certain features, you must register for an account. You agree to:</p><ul><li>Provide accurate and complete registration information</li><li>Maintain the security of your password and account</li><li>Notify us immediately of any unauthorized access</li><li>Accept responsibility for all activity under your account</li></ul><p>We reserve the right to suspend or terminate accounts that violate these terms.</p><h3>4. Certification Program</h3><p>Our Training Hub offers professional certification programs. By participating, you agree to:</p><ul><li>Complete all required sessions and assessments independently</li><li>Not share assessment questions or answers with others</li><li>Not use automated tools or third-party assistance during assessments</li><li>Accept that certificates are issued based on successful completion of all requirements</li></ul><p>Certificates are issued by Financial Modeler Pro, a platform of PaceMakers Business Consultants LLP. We reserve the right to revoke certificates if we determine they were obtained through dishonest means.</p><h3>5. Intellectual Property</h3><p>All content on the Platform &mdash; including courses, videos, assessments, articles, tools, software, logos, and design &mdash; is the intellectual property of PMBC or its licensors. You may not:</p><ul><li>Copy, reproduce, or distribute Platform content without written permission</li><li>Record, download, or capture video content beyond what the Platform allows</li><li>Use our branding, logos, or trademarks without authorization</li><li>Reverse-engineer or attempt to extract source code from the Platform</li></ul><p>Your certificates and badges are yours to share and display professionally.</p><h3>6. Acceptable Use</h3><p>You agree not to:</p><ul><li>Use the Platform for any unlawful purpose</li><li>Attempt to gain unauthorized access to other accounts or Platform systems</li><li>Interfere with the Platform''s operation or security</li><li>Submit false information or impersonate others</li><li>Share your account credentials with others</li><li>Use the Platform to spam, harass, or harm others</li></ul><h3>7. Content You Submit</h3><p>By submitting content to the Platform (comments, feedback, notes), you grant us a non-exclusive, royalty-free license to use that content in connection with operating and improving the Platform. You retain ownership of your content.</p><h3>8. Third-Party Links and Content</h3><p>The Platform may contain links to third-party websites and services, including YouTube for video content. We are not responsible for the content, privacy practices, or availability of third-party services.</p><h3>9. Disclaimer of Warranties</h3><p>The Platform is provided &ldquo;as is&rdquo; and &ldquo;as available.&rdquo; We make no warranties, express or implied, regarding:</p><ul><li>The accuracy or completeness of course content</li><li>Uninterrupted or error-free Platform operation</li><li>The suitability of certifications for any particular employment or professional purpose</li><li>Results you may achieve from using the Platform</li></ul><p>Financial models and techniques taught on the Platform are for educational purposes. You are responsible for validating any models before use in professional settings.</p><h3>10. Limitation of Liability</h3><p>To the maximum extent permitted by law, PMBC shall not be liable for any indirect, incidental, special, consequential, or punitive damages arising from your use of the Platform, including but not limited to:</p><ul><li>Loss of profits, data, or business opportunities</li><li>Decisions made based on Platform content or financial models</li><li>Inability to access the Platform</li><li>Unauthorized access to your account</li></ul><h3>11. Modifications to Terms</h3><p>We may update these Terms of Service at any time. Continued use of the Platform after changes constitutes acceptance of the revised terms. We will notify registered users of significant changes via email.</p><h3>12. Governing Law</h3><p>These terms shall be governed by and construed in accordance with the laws of Pakistan. Any disputes arising from these terms shall be subject to the jurisdiction of the courts in Pakistan.</p><h3>13. Contact Us</h3><p>For questions about these Terms of Service, contact us at:</p><ul><li>Email: <a href=\"mailto:support@financialmodelerpro.com\">support@financialmodelerpro.com</a></li><li>Website: <a href=\"https://financialmodelerpro.com\">financialmodelerpro.com</a></li><li>Parent Company: PaceMakers Business Consultants LLP (<a href=\"https://www.pacemakersglobal.com\">www.pacemakersglobal.com</a>)</li></ul>"
}'::jsonb);

-- ═══════════════════════════════════════════════════════════════════════════════
-- CONFIDENTIALITY & TERMS
-- ═══════════════════════════════════════════════════════════════════════════════
INSERT INTO page_sections (page_slug, section_type, display_order, visible, content) VALUES
('confidentiality', 'rich_text', 1, true, '{
  "heading": "Confidentiality & Terms",
  "badge": "Last Updated: April 2026",
  "html": "<h3>1. Scope</h3><p>This Confidentiality Agreement applies to all users of Financial Modeler Pro (&ldquo;Platform&rdquo;), operated by PaceMakers Business Consultants LLP (&ldquo;PMBC&rdquo;). It governs the treatment of confidential information shared through the Platform.</p><h3>2. Confidential Information</h3><p>Confidential information includes but is not limited to:</p><ul><li>Assessment questions, answers, and scoring criteria</li><li>Financial model templates, formulas, and methodologies</li><li>Course materials, video content, and instructional resources</li><li>Platform source code, algorithms, and technical infrastructure</li><li>Student records, scores, and certification data</li><li>Business strategies, pricing, and internal communications</li></ul><h3>3. Your Obligations</h3><p>As a user of the Platform, you agree to:</p><ul><li>Keep assessment content confidential and not share questions or answers with others</li><li>Not record, screenshot, or distribute course video content</li><li>Not reproduce or redistribute financial model templates or tools</li><li>Treat other students'' information as confidential</li><li>Report any unauthorized disclosure of confidential information to <a href=\"mailto:support@financialmodelerpro.com\">support@financialmodelerpro.com</a></li></ul><h3>4. What You May Share</h3><p>You are encouraged to:</p><ul><li>Share your certificates, badges, and achievement cards on professional networks</li><li>Discuss general concepts and frameworks learned on the Platform</li><li>Recommend the Platform to colleagues and peers</li><li>Share your transcript link with employers or educational institutions</li></ul><h3>5. Our Obligations</h3><p>We commit to:</p><ul><li>Protecting your personal data in accordance with our Privacy Policy</li><li>Not sharing your individual assessment scores or progress with other students</li><li>Not selling your personal information to third parties</li><li>Securing your data with industry-standard encryption and access controls</li><li>Processing your data only for the purposes described in our Privacy Policy</li></ul><h3>6. Duration</h3><p>These confidentiality obligations survive the termination of your account and continue indefinitely for proprietary content such as assessment questions and financial model templates.</p><h3>7. Breach</h3><p>Breach of these confidentiality terms may result in:</p><ul><li>Immediate suspension or termination of your Platform account</li><li>Revocation of issued certificates</li><li>Legal action to protect our intellectual property and proprietary content</li></ul><h3>8. Contact Us</h3><p>For questions about this Confidentiality Agreement, contact us at:</p><ul><li>Email: <a href=\"mailto:support@financialmodelerpro.com\">support@financialmodelerpro.com</a></li><li>Website: <a href=\"https://financialmodelerpro.com\">financialmodelerpro.com</a></li><li>Parent Company: PaceMakers Business Consultants LLP (<a href=\"https://www.pacemakersglobal.com\">www.pacemakersglobal.com</a>)</li></ul>"
}'::jsonb);

