-- REFUND POLICY (draft — hidden from public)
-- ═══════════════════════════════════════════════════════════════════════════════
INSERT INTO page_sections (page_slug, section_type, display_order, visible, content) VALUES
('refund-policy', 'rich_text', 1, true, '{
  "heading": "Refund Policy",
  "badge": "Last Updated: April 2026",
  "html": "<h3>1. Overview</h3><p>This Refund Policy applies to paid services on Financial Modeler Pro (&ldquo;Platform&rdquo;), operated by PaceMakers Business Consultants LLP (&ldquo;PMBC&rdquo;).</p><h3>2. Free Services</h3><p>Our Training Hub certification programs are provided free of charge. No refund applies to free services.</p><h3>3. Paid Subscriptions</h3><p>For paid subscription plans on the Modeling Hub and other premium platforms:</p><p><strong>Cancellation:</strong> You may cancel your subscription at any time from your account settings. Your access continues until the end of the current billing period.</p><p><strong>Refund Window:</strong> If you are not satisfied with a paid subscription, you may request a full refund within 7 days of your initial purchase. After 7 days, no refunds will be issued for the current billing period.</p><p><strong>How to Request:</strong> Send your refund request to <a href=\"mailto:support@financialmodelerpro.com\">support@financialmodelerpro.com</a> with your registered email address and reason for the request. We will process eligible refunds within 10 business days.</p><h3>4. One-Time Purchases</h3><p>For one-time purchases (e.g., individual platform access, downloadable resources):</p><p><strong>Refund Window:</strong> You may request a full refund within 7 days of purchase if you have not substantially used the product.</p><p><strong>Non-Refundable:</strong> Purchases are non-refundable after 7 days or if you have accessed more than 25% of the purchased content.</p><h3>5. Exceptions</h3><p>Refunds will not be issued for:</p><ul><li>Certificates already issued (certificates are earned, not purchased)</li><li>Services already fully rendered</li><li>Accounts suspended or terminated due to violation of our Terms of Service</li><li>Duplicate purchases (we will issue a credit instead)</li></ul><h3>6. Chargebacks</h3><p>If you initiate a chargeback instead of contacting us, we reserve the right to suspend your account pending investigation. We encourage you to contact us first at <a href=\"mailto:support@financialmodelerpro.com\">support@financialmodelerpro.com</a> to resolve any billing concerns.</p><h3>7. Changes to This Policy</h3><p>We may update this Refund Policy when we introduce new paid services. Current users will be notified of significant changes via email.</p><h3>8. Contact Us</h3><p>For refund requests or billing questions, contact us at:</p><ul><li>Email: <a href=\"mailto:support@financialmodelerpro.com\">support@financialmodelerpro.com</a></li><li>Website: <a href=\"https://financialmodelerpro.com\">financialmodelerpro.com</a></li><li>Parent Company: PaceMakers Business Consultants LLP (<a href=\"https://www.pacemakersglobal.com\">www.pacemakersglobal.com</a>)</li></ul>"
}'::jsonb);
